import 'package:go_router/go_router.dart';\nimport 'package:flutter_riverpod/flutter_riverpod.dart';\nimport 'package:kjt_live/screens/auth/login_screen.dart';\nimport 'package:kjt_live/screens/auth/register_screen.dart';\nimport 'package:kjt_live/screens/home/home_screen.dart';\nimport 'package:kjt_live/screens/rooms/rooms_screen.dart';\nimport 'package:kjt_live/screens/rooms/room_detail_screen.dart';\nimport 'package:kjt_live/screens/profile/profile_screen.dart';\n\nfinal goRouterProvider = Provider<GoRouter>((ref) {\n  return GoRouter(\n    routes: [\n      GoRoute(\n        path: '/login',\n        builder: (context, state) => LoginScreen(),\n      ),\n      GoRoute(\n        path: '/register',\n        builder: (context, state) => RegisterScreen(),\n      ),\n      GoRoute(\n        path: '/',\n        builder: (context, state) => HomeScreen(),\n      ),\n      GoRoute(\n        path: '/rooms',\n        builder: (context, state) => RoomsScreen(),\n      ),\n      GoRoute(\n        path: '/rooms/:id',\n        builder: (context, state) {\n          final roomId = state.pathParameters['id']!;\n          return RoomDetailScreen(roomId: roomId);\n        },\n      ),\n      GoRoute(\n        path: '/profile',\n        builder: (context, state) => ProfileScreen(),\n      ),\n    ],\n    initialLocation: '/login',\n  );\n});\n